"""Check for name collisions when merging stages/*.md into references/."""
from pathlib import Path

for skill in sorted(Path('src').glob('skf-*')):
    stages = skill / 'stages'
    references = skill / 'references'
    if not stages.is_dir():
        continue
    stage_names = {f.name for f in stages.rglob('*.md')}
    if not references.is_dir():
        print(f"{skill.name}: no references/ dir (safe — will create)")
        continue
    ref_names = {f.name for f in references.rglob('*.md')}
    collisions = stage_names & ref_names
    if collisions:
        print(f"{skill.name}: COLLISIONS {collisions}")
    else:
        print(f"{skill.name}: clean ({len(stage_names)} stage + {len(ref_names)} ref)")
