#!/usr/bin/env python3
"""Rewrite `stages/` path references to `references/` across tracked SKF files."""
import re
from pathlib import Path

PAT = re.compile(r'\bstages/')

EXCLUDE_DIRS = {'.git', '.claude', '.analysis', 'node_modules', '_bmad-output', '_bmad', 'forge-data', '.entire'}
INCLUDE_EXT = {'.md', '.py', '.js', '.cjs', '.mjs', '.ts', '.yaml', '.yml', '.toml', '.json', '.txt'}

def should_skip(p):
    return any(part in EXCLUDE_DIRS for part in p.parts)

changed = 0
total = 0
for p in sorted(Path('.').rglob('*')):
    if not p.is_file() or should_skip(p) or p.suffix not in INCLUDE_EXT:
        continue
    try:
        t = p.read_text(encoding='utf-8')
    except Exception:
        continue
    if 'stages/' not in t:
        continue
    new, n = PAT.subn('references/', t)
    if new != t:
        p.write_text(new, encoding='utf-8')
        changed += 1
        total += n
print(f"{changed} files, {total} subs")
PYEOF
python3 /tmp/skf-rewrite-stages-to-refs.py

